//! Bundled single-page chat UI for the Forge MVP.

pub const CHAT_HTML: &str = r##"<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Forge Unified</title>
<style>
:root{color-scheme:dark;--bg:#0b1020;--panel:#111a2e;--panel2:#18233a;--text:#edf4ff;--muted:#9fb0d0;--border:#2a3858;--accent:#67e8f9;--ok:#86efac;--danger:#fb7185;--add:#86efac;--edit:#67e8f9;--del:#fb7185;--move:#fde68a}*{box-sizing:border-box}body{margin:0;min-height:100vh;background:radial-gradient(circle at top left,#1e3a5f 0,var(--bg) 42rem);color:var(--text);font:15px/1.45 system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}button,textarea{font:inherit}button{border:1px solid var(--border);background:var(--panel2);color:var(--text);border-radius:12px;padding:.65rem .9rem;cursor:pointer}button.primary{background:var(--accent);color:#04111f;border-color:transparent;font-weight:800}button:disabled{opacity:.55}.app{display:grid;grid-template-columns:minmax(240px,320px) minmax(0,1fr);height:100vh}aside{border-right:1px solid var(--border);background:rgba(17,26,46,.9);padding:1rem;display:flex;flex-direction:column;gap:1rem;min-height:0}main{display:grid;grid-template-rows:auto 1fr auto;min-height:0}.brand{display:flex;justify-content:space-between;gap:1rem}h1{font-size:1.2rem;margin:0}.muted,.subtitle{color:var(--muted);font-size:.84rem}.pill{border:1px solid var(--border);border-radius:999px;padding:.22rem .55rem;color:var(--muted);font-size:.78rem}.conv-list{display:flex;flex-direction:column;gap:.45rem;overflow:auto}.conv{text-align:left;border-radius:14px;padding:.75rem}.conv.active{border-color:var(--accent);box-shadow:0 0 0 1px rgba(103,232,249,.22) inset}.conv-title{font-weight:800;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.topbar,.composer{border-color:var(--border);background:rgba(11,16,32,.88);padding:1rem clamp(1rem,3vw,1.5rem)}.topbar{border-bottom:1px solid var(--border);display:flex;justify-content:space-between;gap:1rem;align-items:center}.composer{border-top:1px solid var(--border)}.messages{padding:1rem clamp(1rem,3vw,1.5rem);overflow:auto;display:flex;flex-direction:column;gap:.8rem;min-height:0}.message{max-width:920px;border:1px solid var(--border);border-radius:18px;padding:.9rem;background:rgba(17,26,46,.84);white-space:pre-wrap;overflow-wrap:anywhere}.message.user{align-self:flex-end;background:rgba(103,232,249,.13);border-color:rgba(103,232,249,.42)}.message.assistant{align-self:flex-start}.message.tool{align-self:stretch;max-width:none;background:rgba(24,35,58,.72)}.role{display:flex;justify-content:space-between;color:var(--muted);font-size:.76rem;margin-bottom:.45rem;text-transform:uppercase;letter-spacing:.04em}.tool-card{border:1px solid rgba(134,239,172,.45);border-radius:14px;padding:.75rem;margin-top:.55rem;background:rgba(0,0,0,.18)}.tool-card.running{border-color:rgba(103,232,249,.6)}.tool-card.error,.tool-card.err{border-color:rgba(251,113,133,.65)}.tool-head{display:flex;justify-content:space-between;gap:1rem;font-weight:800;color:var(--ok)}.tool-card.running .tool-head{color:var(--accent)}.tool-card.error .tool-head,.tool-card.err .tool-head{color:var(--danger)}.tool-output{margin-top:.55rem;color:#d9e7ff}.tool-card details{margin-top:.55rem;color:var(--muted)}.tool-card summary{cursor:pointer}.tool-card pre{margin:.5rem 0 0;padding:.75rem;border-radius:12px;background:#050914;overflow:auto;max-height:11rem;color:#d9e7ff}.file-events{display:grid;gap:.45rem;margin-top:.65rem}.file-card{border:1px solid var(--border);border-radius:12px;background:rgba(5,9,20,.74);padding:.65rem;display:grid;gap:.35rem}.file-card.add{border-color:rgba(134,239,172,.55)}.file-card.edit{border-color:rgba(103,232,249,.55)}.file-card.delete{border-color:rgba(251,113,133,.6)}.file-card.move{border-color:rgba(253,230,138,.6)}.file-title{display:flex;gap:.5rem;align-items:center;font-weight:800}.file-badge{border-radius:999px;padding:.1rem .45rem;background:rgba(255,255,255,.08);font-size:.74rem}.file-card.add .file-badge{color:var(--add)}.file-card.edit .file-badge{color:var(--edit)}.file-card.delete .file-badge{color:var(--del)}.file-card.move .file-badge{color:var(--move)}.file-path{font-family:ui-monospace,SFMono-Regular,Menlo,Consolas,monospace;overflow-wrap:anywhere}.file-meta{color:var(--muted);font-size:.78rem}.composer-inner{display:grid;grid-template-columns:1fr auto;gap:.75rem;align-items:end}textarea{width:100%;min-height:4.5rem;max-height:12rem;resize:vertical;border-radius:16px;border:1px solid var(--border);color:var(--text);background:rgba(17,26,46,.92);padding:.85rem}.toast{position:fixed;right:1rem;bottom:1rem;display:none;background:#09111f;border:1px solid var(--border);border-radius:16px;padding:.8rem .9rem}.toast.show{display:block}@media(max-width:780px){.app{grid-template-columns:1fr}aside{max-height:36vh;border-right:0;border-bottom:1px solid var(--border)}.composer-inner{grid-template-columns:1fr}}
</style>
</head>
<body>
<div class="app">
<aside><div class="brand"><div><h1>Forge Unified</h1><div class="subtitle">Chat-first coding app MVP.</div></div><span class="pill" id="health-pill">checking</span></div><button id="new-conversation" class="primary">New conversation</button><div class="muted"><strong id="conversation-count">0</strong> conversations · <strong id="message-count">0</strong> messages</div><div class="conv-list" id="conversation-list"></div></aside>
<main><div class="topbar"><div><strong id="chat-title">No conversation selected</strong><div class="subtitle" id="chat-subtitle">Persistent chat id appears here.</div></div><div><button id="refresh">Refresh</button> <button id="snapshot" disabled>Save snapshot</button> <button id="graph">Graph</button></div></div><section class="messages" id="messages" aria-live="polite"></section><div class="composer"><div class="composer-inner"><label><span class="subtitle">Message</span><textarea id="message-input" placeholder="Ask Forge to inspect files, edit code, or create a proof note." disabled></textarea></label><button id="send" class="primary" disabled>Send</button></div><div class="subtitle">file-change file-card · OpenCode ToolPart cards · metadata in details</div></div></main>
</div><div class="toast" id="toast"></div>
<script>
const state={conversations:[],activeId:null,activeConversation:null,busy:false,streamAssistant:null};const $=id=>document.getElementById(id);
function toast(message,kind=''){const el=$('toast');el.textContent=message;el.className='toast show '+kind;clearTimeout(toast.timer);toast.timer=setTimeout(()=>el.className='toast',4200)}
async function api(path,options={}){const r=await fetch(path,{headers:{'content-type':'application/json',...(options.headers||{})},...options});const text=await r.text();let data=null;try{data=text?JSON.parse(text):null}catch{data=text}if(!r.ok)throw new Error(`${r.status} ${r.statusText}: ${typeof data==='string'?data:JSON.stringify(data)}`);return data}
async function checkHealth(){try{const h=await api('/api/health');$('health-pill').textContent=h.status||'ok'}catch{$('health-pill').textContent='offline'}}
async function loadConversations(selectFirst=false){state.conversations=await api('/api/conversations');$('conversation-count').textContent=String(state.conversations.length);renderConversationList();if(!state.activeId&&selectFirst&&state.conversations.length)await selectConversation(state.conversations[0].id)}
function renderConversationList(){const list=$('conversation-list');list.innerHTML='';for(const conv of state.conversations){const b=document.createElement('button');b.className='conv'+(conv.id===state.activeId?' active':'');b.innerHTML='<div class="conv-title"></div><div class="muted"></div>';b.querySelector('.conv-title').textContent=conv.title||'Untitled';b.querySelector('.muted').textContent=`${conv.message_count} messages · ${conv.mode}`;b.onclick=()=>selectConversation(conv.id);list.appendChild(b)}}
async function createConversation(){const c=await api('/api/conversations',{method:'POST',body:JSON.stringify({title:`Forge run ${new Date().toLocaleString()}`})});state.activeId=c.id;await loadConversations(false);await selectConversation(c.id);toast('Conversation created')}
async function selectConversation(id){state.activeId=id;state.activeConversation=await api(`/api/conversations/${encodeURIComponent(id)}`);$('chat-title').textContent=state.activeConversation.title||'Untitled';$('chat-subtitle').textContent=id;$('message-input').disabled=false;$('send').disabled=state.busy;$('snapshot').disabled=false;$('message-count').textContent=String((state.activeConversation.messages||[]).length);renderConversationList();renderMessages()}
function renderMessages(){const c=$('messages');c.innerHTML='';const messages=state.activeConversation?.messages||[];if(!messages.length){c.innerHTML='<div class="message assistant"><strong>Ready to build</strong><br>Ask Forge to inspect files, edit code, or create a proof note.</div>';return}for(const msg of messages)c.appendChild(renderMessage(msg));c.scrollTop=c.scrollHeight}
function renderMessage(msg){const a=document.createElement('article');const role=(msg.role||'unknown').toLowerCase();a.className=`message ${role}`;a.innerHTML='<div class="role"><span></span><span></span></div>';a.querySelector('.role span').textContent=role;if(msg.content){const body=document.createElement('div');body.textContent=msg.content;a.appendChild(body)}const parts=msg?.metadata?.tool_parts||[];if(parts.length){for(const part of parts)a.appendChild(toolPartCard(part));return a}const all=[];for(const res of msg.tool_results||[])for(const ev of res?.metadata?.file_events||[])all.push(ev);if(all.length)a.appendChild(fileEventsBlock(all));for(const res of msg.tool_results||[])a.appendChild(toolCard(res));return a}
function toolPartCard(part){const st=part.state||{};const status=st.status||'completed';const meta=st.metadata||{};const card=document.createElement('div');card.className='tool-card '+status;card.innerHTML='<div class="tool-head"><span></span><span></span></div>';card.querySelector('.tool-head span').textContent=String(st.title||part.tool||'tool');card.querySelector('.tool-head span:last-child').textContent=status;const events=meta.file_events||[];if(events.length)card.appendChild(fileEventsBlock(events));const out=document.createElement('div');out.className='tool-output';out.textContent=compact(st.output||st.error||'Completed.');card.appendChild(out);const details=document.createElement('details');details.innerHTML='<summary>OpenCode ToolPart metadata</summary>';const pre=document.createElement('pre');pre.textContent=JSON.stringify(part,null,2);details.appendChild(pre);card.appendChild(details);return card}
function toolCard(payload){const ok=payload.success!==false;const card=document.createElement('div');card.className='tool-card '+(ok?'ok':'err');card.innerHTML='<div class="tool-head"><span></span><span></span></div>';card.querySelector('.tool-head span').textContent=title(payload);card.querySelector('.tool-head span:last-child').textContent=ok?'done':'failed';const events=payload?.metadata?.file_events||[];if(events.length)card.appendChild(fileEventsBlock(events));const out=document.createElement('div');out.className='tool-output';out.textContent=compact(payload.output||payload.error||'Completed.');card.appendChild(out);const details=document.createElement('details');details.innerHTML='<summary>metadata</summary>';const pre=document.createElement('pre');pre.textContent=JSON.stringify(payload,null,2);details.appendChild(pre);card.appendChild(details);return card}
function title(payload){return String(payload?.metadata?.title||payload?.kind||payload?.name||'tool')}
function compact(text){const value=String(text);return value.length>260?value.slice(0,260)+'…':value}
function fileEventsBlock(events){const wrap=document.createElement('div');wrap.className='file-events';for(const ev of events)wrap.appendChild(fileEventCard(ev));return wrap}
function fileEventCard(ev){const short=String(ev.type||'file.edited').replace('file.','');const cls=short==='added'?'add':short==='deleted'?'delete':short==='moved'?'move':'edit';const card=document.createElement('div');card.className='file-card '+cls;card.innerHTML='<div class="file-title"><span class="file-badge"></span><span class="file-path"></span></div><div class="file-meta"></div>';card.querySelector('.file-badge').textContent=short.toUpperCase();card.querySelector('.file-path').textContent=ev.previousPath&&ev.path?`${ev.previousPath} → ${ev.path}`:(ev.path||'unknown file');card.querySelector('.file-meta').textContent=`+${ev.additions||0} / -${ev.deletions||0}${ev.bom?' · BOM':''}${ev.source?' · '+ev.source:''}`;return card}
function appendUser(text){const a=document.createElement('article');a.className='message user';a.innerHTML='<div class="role"><span>user</span><span>stream</span></div>';const b=document.createElement('div');b.textContent=text;a.appendChild(b);$('messages').appendChild(a)}
function ensureAssistant(){if(state.streamAssistant)return state.streamAssistant;const a=document.createElement('article');a.className='message assistant';a.innerHTML='<div class="role"><span>assistant</span><span>SSE</span></div><div class="stream-text"></div>';$('messages').appendChild(a);state.streamAssistant=a.querySelector('.stream-text');return state.streamAssistant}
function handleEvent(name,data){if(name==='run-start')toast('Run started');else if(name==='text-delta')ensureAssistant().textContent+=data.text||'';else if(name==='tool-result'||name==='tool-error')$('messages').appendChild(toolCard(data));else if(name==='file-change')$('messages').appendChild(fileEventCard(data));else if(name==='provider-error')toast(data.message||'provider error','error');else if(name==='conversation'){state.activeConversation=data;$('message-count').textContent=String((data.messages||[]).length)}else if(name==='run-finish')toast('Run finished');$('messages').scrollTop=$('messages').scrollHeight}
async function readSse(response){const reader=response.body.getReader();const decoder=new TextDecoder();let buffer='';while(true){const {value,done}=await reader.read();if(done)break;buffer+=decoder.decode(value,{stream:true});let parts=buffer.split('\n\n');buffer=parts.pop();for(const part of parts){let event='message',data='';for(const line of part.split('\n')){if(line.startsWith('event:'))event=line.slice(6).trim();if(line.startsWith('data:'))data+=line.slice(5).trim()}try{handleEvent(event,data?JSON.parse(data):{})}catch(e){toast(e.message,'error')}}}}
async function sendMessage(){const input=$('message-input');const message=input.value.trim();if(!state.activeId||!message||state.busy)return;state.busy=true;state.streamAssistant=null;input.value='';$('send').disabled=true;input.disabled=true;if(!$('messages').children.length)$('messages').innerHTML='';appendUser(message);try{const r=await fetch(`/api/conversations/${encodeURIComponent(state.activeId)}/chat/stream`,{method:'POST',headers:{'content-type':'application/json','accept':'text/event-stream'},body:JSON.stringify({message,max_rounds:10})});if(!r.ok)throw new Error(`stream failed ${r.status}`);await readSse(r);await selectConversation(state.activeId);await loadConversations(false)}catch(err){toast(err.message,'error')}finally{state.busy=false;input.disabled=!state.activeId;$('send').disabled=!state.activeId}}
async function saveSnapshot(){if(!state.activeId)return;await api(`/api/conversations/${encodeURIComponent(state.activeId)}/snapshot`,{method:'POST',body:'{}'});toast('Snapshot saved')}
$('new-conversation').onclick=()=>createConversation().catch(e=>toast(e.message,'error'));$('refresh').onclick=()=>Promise.all([loadConversations(false),state.activeId?selectConversation(state.activeId):null]).catch(e=>toast(e.message,'error'));$('snapshot').onclick=()=>saveSnapshot().catch(e=>toast(e.message,'error'));$('graph').onclick=()=>{window.location.href='/api/graph'};$('send').onclick=()=>sendMessage();$('message-input').addEventListener('keydown',e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();sendMessage()}});checkHealth();loadConversations(true).catch(e=>toast(e.message,'error'));
</script>
</body>
</html>"##;
